import React, { useState, useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import Login from './pages/Login';
import Register from './pages/Register';
import Dashboard from './pages/Dashboard';
import Applications from './pages/Applications';
import CoverLetter from './pages/CoverLetter';
import JobMatcher from './pages/JobMatcher';
import Profile from './pages/Profile';
import AIDashboard from './pages/JS AIDashboard';
import UploadResume from './pages/UploadResume';
import './App.css';

function App(){
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('token'));

    useEffect(() => {
        if(token){
            fetchUser();
        }
    }, [token]);

    const fetchUser = async () => {
        try{
            const res = await fetch('/api/auth/profile', {
                headers: { 'Authorization': token }
            });
            if(res.ok){
                const data = await res.json();
                setUser(data);
            }else{
                logout();
            }
        }catch(err){
            logout();
        }
    };

    const login = async (email, password) => {
        const res = await fetch('/api/auth/login', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ email, password })
        });
        const data = await res.json();
        if(res.ok){
            localStorage.setItem('token', data.token);
            setToken(data.token);
            setUser(data.user);
            return true;
        }
        return false;
    };

    const register = async (name, email, password) => {
        const res = await fetch('/api/auth/register', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ name, email, password })
        });
        const data = await res.json();
        if(res.ok){
            localStorage.setItem('token', data.token);
            setToken(data.token);
            setUser(data.user);
            return true;
        }
        return false;
    };

    const logout = () => {
        localStorage.removeItem('token');
        setToken(null);
        setUser(null);
    };

    const Navbar = () => {
        if(!user){
            return null;
        }
        return(
            <nav className="navbar">
                <div className="container">
                    <Link to="/" className="logo">JobAssistant</Link>
                    <div className="nav-links">
                        <Link to="/">Dashboard</Link>
                        <Link to="/upload-resume">📄 Upload Resume</Link>
                        <Link to="/applications">Applications</Link>
                        <Link to="/cover-letter">Cover Letter</Link>
                        <Link to="/ai-dashboard">🤖 AI Dashboard</Link>
                        <Link to="/job-matcher">Job Matcher</Link>
                        <Link to="/profile">Profile</Link>
                        <button onClick={logout} className="logout-btn">Logout</button>
                    </div>
                </div>
            </nav>
        );
    };

    return(
        <BrowserRouter>
            <Navbar />
            <div className="container">
                <Routes>
                    <Route path="/login" element={!user ? <Login onLogin={login} /> : <Navigate to="/" />} />
                    <Route path="/register" element={!user ? <Register onRegister={register} /> : <Navigate to="/" />} />
                    <Route path="/" element={user ? <Dashboard token={token} /> : <Navigate to="/login" />} />
                    <Route path="/applications" element={user ? <Applications token={token} /> : <Navigate to="/login" />} />
                    <Route path="/cover-letter" element={user ? <CoverLetter token={token} /> : <Navigate to="/login" />} />
                    <Route path="/job-matcher" element={user ? <JobMatcher token={token} /> : <Navigate to="/login" />} />
                    <Route path="/profile" element={user ? <Profile token={token} /> : <Navigate to="/login" />} />
                    <Route path="/ai-dashboard" element={<AIDashboard />} />
                    <Route path="/upload-resume" element={<UploadResume />} />
                </Routes>
            </div>
        </BrowserRouter>
    );
}

export default App;
